const SUPPORTED_LANGS = ['en', 'de', 'es'];
let currentLang = localStorage.getItem('ctwp-lang');
if (!SUPPORTED_LANGS.includes(currentLang)) currentLang = 'en';

function t(key) {
  return (translations[currentLang] && translations[currentLang][key]) || translations['en'][key] || key;
}

function applyTranslations() {
  /* Text content */
  document.querySelectorAll('[data-i18n]').forEach(el => {
    el.textContent = t(el.dataset.i18n);
  });
  /* HTML content (for elements with tags like <em>) */
  document.querySelectorAll('[data-i18n-html]').forEach(el => {
    el.innerHTML = t(el.dataset.i18nHtml);
  });
  /* Placeholders */
  document.querySelectorAll('[data-i18n-ph]').forEach(el => {
    el.placeholder = t(el.dataset.i18nPh);
  });
  /* Class-based translation for repeated UI elements (pricing pills + Top Pick badge) */
  document.querySelectorAll('.pricing-pill.pill-free').forEach(el => { el.textContent = t('pill.free'); });
  document.querySelectorAll('.pricing-pill.pill-free-signup').forEach(el => { el.textContent = t('pill.free_signup'); });
  document.querySelectorAll('.pricing-pill.pill-freemium').forEach(el => { el.textContent = t('pill.freemium'); });
  document.querySelectorAll('.top-pick-badge').forEach(el => {
    el.innerHTML = '<i class="fas fa-star"></i> ' + t('top_pick');
  });
  /* University audience-grade badges */
  document.querySelectorAll('.grade-badge.gb-undergrad').forEach(el => { el.textContent = t('uni.grade.undergrad'); });
  document.querySelectorAll('.grade-badge.gb-grad').forEach(el => { el.textContent = t('uni.grade.grad'); });
  document.querySelectorAll('.grade-badge.gb-phd').forEach(el => { el.textContent = t('uni.grade.phd'); });
  document.querySelectorAll('.grade-badge.gb-self').forEach(el => { el.textContent = t('uni.grade.self'); });
  document.querySelectorAll('.grade-badge.gb-adult').forEach(el => { el.textContent = t('uni.grade.adult'); });
  document.querySelectorAll('.grade-badge.gb-switcher').forEach(el => { el.textContent = t('uni.grade.switcher'); });
  /* Teachers audience-stage badges + gb-all (page-aware) */
  var _allKey = location.pathname.endsWith('teachers.html') ? 'teachers.grade.all' : 'uni.grade.all';
  document.querySelectorAll('.grade-badge.gb-all').forEach(el => { el.textContent = t(_allKey); });
  document.querySelectorAll('.grade-badge.gb-prek').forEach(el => { el.textContent = t('teachers.grade.prek'); });
  document.querySelectorAll('.grade-badge.gb-primary').forEach(el => { el.textContent = t('teachers.grade.primary'); });
  document.querySelectorAll('.grade-badge.gb-secondary').forEach(el => { el.textContent = t('teachers.grade.secondary'); });
  document.querySelectorAll('.grade-badge.gb-higher').forEach(el => { el.textContent = t('teachers.grade.higher'); });
  document.querySelectorAll('.grade-badge.gb-sen').forEach(el => { el.textContent = t('teachers.grade.sen'); });
  /* Update toggle button — highlight active language */
  const btn = document.getElementById('langToggle');
  if (btn) {
    btn.querySelectorAll('.lang-opt').forEach(opt => {
      opt.classList.toggle('lang-active', opt.dataset.lang === currentLang);
    });
  }
  /* Update html lang attribute */
  document.documentElement.lang = currentLang;
}

function setLanguage(lang) {
  if (!SUPPORTED_LANGS.includes(lang)) return;
  currentLang = lang;
  localStorage.setItem('ctwp-lang', lang);
  applyTranslations();
}

function i18nInit() {
  applyTranslations();
  const btn = document.getElementById('langToggle');
  if (!btn) return;
  // Each .lang-opt is clickable individually
  btn.querySelectorAll('.lang-opt').forEach(opt => {
    opt.addEventListener('click', (e) => {
      e.stopPropagation();
      setLanguage(opt.dataset.lang);
    });
  });
}

if (document.readyState === 'loading') {
  document.addEventListener('DOMContentLoaded', i18nInit);
} else {
  i18nInit();
}
